### Physics Engine

**`a0_0x3352fa` — Force calculation (runs each tick):**
```javascript
function updatePhysics() {
    // 1. Node-node repulsion (inverse-square law)
    for (i = 0; i < nodes.length; i++) {
        for (j = i + 1; j < nodes.length; j++) {
            var dx = nodes[i].x - nodes[j].x;
            var dy = nodes[i].y - nodes[j].y;
            var dist = Math.sqrt(dx*dx + dy*dy) || 1;
            var force = attraction / (dist * dist);
            var fx = (dx / dist) * force;
            var fy = (dy / dist) * force;
            nodes[i].vx += fx;  nodes[i].vy += fy;
            nodes[j].vx -= fx;  nodes[j].vy -= fy;
        }
    }

    // 2. Spring forces along edges (Hooke's law)
    for (e = 0; e < edges.length; e++) {
        var nodeA = findNode(edges[e].a);
        var nodeB = findNode(edges[e].b);
        var dx = nodeB.x - nodeA.x;
        var dy = nodeB.y - nodeA.y;
        var dist = Math.sqrt(dx*dx + dy*dy) || 1;
        var displacement = dist - edges[e].rest;
        var force = (edges[e].k || tensionCoefficient) * displacement;
        nodeA.vx += (dx/dist) * force;
        nodeA.vy += (dy/dist) * force;
        nodeB.vx -= (dx/dist) * force;
        nodeB.vy -= (dy/dist) * force;
    }

    // 3. Center gravity + damping + position update
    for (i = 0; i < nodes.length; i++) {
        nodes[i].vx += (400 - nodes[i].x) * centerReversal;
        nodes[i].vy += (300 - nodes[i].y) * centerReversal;
        nodes[i].vx *= velocityDamping;
        nodes[i].vy *= velocityDamping;
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}
```

### Particle System

**`a0_0x4c7566` — Spawn particle:**
```javascript
function spawnParticle() {
    if (particles.length >= stream_count) return;
    var angle = Math.random() * TAU;
    var speed = 0.3 + Math.random() * SQRT_HALF;
    var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
    particles.push({
        x: sourceNode.x, y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT_HALF
    });
}
```

**`a0_0x3585f9` — Update particles:**
```javascript
function updateParticles() {
    for (var i = particles.length - 1; i >= 0; i--) {
        var p = particles[i];
        p.vx *= (1 - stream_decay * 0.125);
        p.vy *= (1 - stream_decay * 0.125);
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}
```

### Camera Smoothing
```javascript
function updateCamera() {
    camera.x += (target.x - camera.x) * theta;
    camera.y += (target.y - camera.y) * theta;
    camera.zoom += (target.zoom - camera.zoom) * theta;
}
```

### Main Loop
```javascript
function tick() {
    frameCount++;
    updatePhysics();
    if (frameCount % 3 === 0) spawnParticle();
    updateParticles();
    updateCamera();
}

setInterval(tick, 16);  // ~60 FPS
```

